#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
    struct Node* prev;
} Node;

void findPairs(Node* head, Node* tail, int target) {
    Node* left = head;
    Node* right = tail;
    int found = 0;
    while (left && right && left->data < right->data) {
        int sum = left->data + right->data;
        if (sum == target) {
            printf("[%d, %d] ", left->data, right->data);
            found = 1;
            left = left->next;
            right = right->prev;
        } else if (sum < target) {
            left = left->next;
        } else {
            right = right->prev;
        }
    }
    if (!found) printf("[]");
    printf("\n");
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node *head = NULL, *tail = NULL;
        for (int i = 0; i < N; ++i) {
            int val; scanf("%d", &val);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->data = val; nd->next = NULL; nd->prev = NULL;
            if (!head) { head = tail = nd; }
            else { tail->next = nd; nd->prev = tail; tail = nd; }
        }
        int target; scanf("%d", &target);
        findPairs(head, tail, target);
        // free list (optional for contest)
        Node* cur = head;
        while (cur) { Node* nxt = cur->next; free(cur); cur = nxt; }
    }
    return 0;
}

