import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int data;
        Node next, prev;
        Node(int d) { data = d; }
    }

    static void findPairs(Node head, Node tail, int target, StringBuilder out) {
        Node left = head, right = tail;
        boolean found = false;
        while (left != null && right != null && left.data < right.data) {
            int sum = left.data + right.data;
            if (sum == target) {
                out.append('[').append(left.data).append(", ").append(right.data).append("] ");
                found = true;
                left = left.next;
                right = right.prev;
            } else if (sum < target) {
                left = left.next;
            } else {
                right = right.prev;
            }
        }
        if (!found) out.append("[]");
        out.append('\n');
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder output = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            StringTokenizer st = new StringTokenizer(br.readLine());
            Node head = null, tail = null;
            for (int i = 0; i < N; ++i) {
                int v = Integer.parseInt(st.nextToken());
                Node nd = new Node(v);
                if (head == null) { head = tail = nd; }
                else { tail.next = nd; nd.prev = tail; tail = nd; }
            }
            int target = Integer.parseInt(br.readLine().trim());
            findPairs(head, tail, target, output);
        }
        System.out.print(output.toString());
    }
}

