import sys

def find_pairs(head, tail, target, out_lines):
    left, right = head, tail
    found = False
    while left and right and left.data < right.data:
        s = left.data + right.data
        if s == target:
            out_lines.append(f"[{left.data}, {right.data}] ")
            found = True
            left = left.next
            right = right.prev
        elif s < target:
            left = left.next
        else:
            right = right.prev
    if not found:
        out_lines.append("[]")
    out_lines.append("\n")

class Node:
    __slots__ = ("data", "next", "prev")
    def __init__(self, data):
        self.data = data
        self.next = None
        self.prev = None


def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        head = tail = None
        for _ in range(N):
            val = int(next(it))
            nd = Node(val)
            if head is None:
                head = tail = nd
            else:
                tail.next = nd
                nd.prev = tail
                tail = nd
        target = int(next(it))
        find_pairs(head, tail, target, out)
    sys.stdout.write(''.join(out))

if __name__ == "__main__":
    main()

